// Extract candidate IDs from the dashboard response
// If the GET endpoint doesn't exist, you can hardcode recently synced candidate IDs
// or query Supabase directly via the Supabase node
const response = $input.first().json;
let candidateIds = [];

// Try parsing from body (full response mode)
const body = response.body || response;
if (Array.isArray(body)) {
  candidateIds = body.map(c => c.id);
} else if (body.candidates && Array.isArray(body.candidates)) {
  candidateIds = body.candidates.map(c => c.id);
} else if (body.data && Array.isArray(body.data)) {
  candidateIds = body.data.map(c => c.id);
}

// Rate limit: max 200 candidates per run to stay within Zoho API limits
const MAX_CANDIDATES = 200;
const limitedIds = candidateIds.slice(0, MAX_CANDIDATES);

// Return each candidate ID as a separate item for the loop
return limitedIds.map(id => ({
  json: {
    candidate_id: id,
    total_candidates: limitedIds.length
  }
}));

// Filter and transform activities to stage_history format
// Only keep Candidate_Status field changes
const items = $input.all();
const allActivities = [];

for (const item of items) {
  const responseBody = item.json.body || item.json;
  const activities = responseBody.data || [];
  const candidateId = item.json.candidate_id || null;

  // Filter for status change activities
  const statusChanges = activities.filter(activity => {
    // Zoho activities that represent field changes
    return (
      activity.field_name === 'Candidate_Status' ||
      activity.field_label === 'Candidate Status' ||
      (activity.activity_type === 'field_update' && 
       (activity.field_name === 'Candidate_Status' || activity.field_name === 'Candidate Stage'))
    );
  });

  for (const change of statusChanges) {
    allActivities.push({
      candidate_id: candidateId || change.parent_id || null,
      job_opening_id: change.job_opening_id || null,
      from_status: change.old_value || change.previous_value || null,
      to_status: change.new_value || change.current_value || null,
      changed_at: change.activity_time || change.Created_Time || change.modified_time || null,
      changed_by: change.done_by ? change.done_by.name : null
    });
  }
}

if (allActivities.length === 0) {
  return [{ json: { activities: [], skip: true, message: 'No status change activities found' } }];
}

// Batch activities in groups of 100 for the API
const BATCH_SIZE = 100;
const batches = [];
for (let i = 0; i < allActivities.length; i += BATCH_SIZE) {
  batches.push(allActivities.slice(i, i + BATCH_SIZE));
}

return batches.map(batch => ({
  json: {
    activities: batch,
    skip: false,
    batch_count: batch.length
  }
}));

// Log completion
return [{
  json: {
    workflow: '03-sync-activities',
    status: 'completed',
    completed_at: new Date().toISOString()
  }
}];

// Log skip
return [{
  json: {
    workflow: '03-sync-activities',
    status: 'skipped',
    reason: 'No status change activities found',
    completed_at: new Date().toISOString()
  }
}];
